import React, { useState } from "react";

import { Send } from "lucide-react";

import "./AIAssistant.css";

export default function AIAssistant() {

const [chatInput, setChatInput] = useState("");

const [messages, setMessages] = useState([]);

function handleSend() {

if (!chatInput.trim()) return;

let reply = "";

const q = chatInput.toLowerCase();

if (q.includes("rice")) {

reply =
"🌾 Rice grows best in June and July. Use NPK fertilizer.";

}

else if (q.includes("rain")) {

reply =
"🌧️ Tomorrow rain probability is 40%.";

}

else if (q.includes("fertilizer")) {

reply =
"🧪 Organic fertilizer is recommended.";

}

else if (q.includes("crop")) {

reply =
"🌱 Rice, Cotton and Maize are profitable this season.";

}

else if (q.includes("price")) {

reply =
"💰 Cotton prices are increasing this week.";

}

else {

reply =
"🤖 Please ask a farming related question.";

}

setMessages(prev => [

...prev,

{

text: chatInput,

user: true

},

{

text: reply,

user: false

}

]);

setChatInput("");

}

return (

<div className="ai-card">

<div className="ai-header">

<div className="ai-avatar">

🤖

</div>

<div>

<h3>

Smart Farmer AI

</h3>

<p>

Your Digital Agriculture Assistant

</p>

</div>

</div>

<div className="ai-suggestions">

<button

onClick={()=>

setChatInput(

"When should I grow rice?"

)

}

>

🌾 Rice

</button>

<button

onClick={()=>

setChatInput(

"Will it rain tomorrow?"

)

}

>

🌧️ Rain

</button>

<button

onClick={()=>

setChatInput(

"Best fertilizer?"

)

}

>

🧪 Fertilizer

</button>

<button

onClick={()=>

setChatInput(

"Best crop this season?"

)

}

>

🌱 Crop

</button>

</div>

<div className="chat-messages">

{messages.length===0 && (

<div className="welcome-box">

<h4>

👋 Welcome Farmer

</h4>

<p>

Ask anything about farming.

</p>

<ul>

<li>🌦️ Weather</li>

<li>🌱 Crops</li>

<li>🧪 Fertilizer</li>

<li>💰 Market Prices</li>

</ul>

</div>

)}

{messages.map((msg,index)=>(

<div

key={index}

className={`chat-msg ${

msg.user

?

"user-msg"

:

"bot-msg"

}`}

>

{msg.text}

</div>

))}

</div>

<div className="ai-input-row">

<input

type="text"

placeholder="Ask a farming question..."

value={chatInput}

onChange={(e)=>

setChatInput(

e.target.value

)

}

onKeyDown={(e)=>

e.key==="Enter"

&& handleSend()

}

/>

<button

className="send-btn"

onClick={handleSend}

>

<Send size={18}/>

</button>

</div>

</div>

);

}
